var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제6방위선 제3 극비 연구 시설","JPN":"人類統合防衛軍第6防衛線、第3極秘研究施設","ENG":"Secret Research Facility No. 3, United Humankind Defense Force's 6th Defense Line","TWN":"人類共同保衛軍第六防線第三機密研究室"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"내 조사가 맞다면, 여기가 그 <color=#ffd34c>학교</color>인가.","JPN":"私の調査が正しければ、ここが例の<color=#ffd34c>学校</color>だな。","ENG":"According to my investigation, this should be the <color=#ffd34c>school</color>.","TWN":"嗯，如果我的調查沒錯的話，這裡就是那個<color=#ffd34c>學校</color>了。"},"stage":{"bg":"SCHOOL_ABANDONED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"연방 정부가 주도한 카운터 양성 계획은 침식 사태의 가속화로 종결처리 되었지만……","JPN":"連邦政府が主導したカウンター養成計画は侵食災害の加速化によって終結してしまったが……","ENG":"The Counter training project the Federal Government was backing got terminated due to the acceleration of the Corruption disaster...","TWN":"聯邦主導的制裁者培育計畫，雖然因侵蝕事件惡化而終止……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 뒤로도 예상대로 비공식적인 카운터 양성 계획은 계속된 모양이군.","JPN":"やはりその後も非公式的なカウンター養成計画は続けられていたようだな。","ENG":"But as expected, it appears that an unofficial Counter training project has continued to operate since then.","TWN":"不過背地裡應該仍然持續在進行非正式的制裁者培育計畫。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 그 기안자는 역시……","JPN":"そしてその発案者も……","ENG":"Also, the drafter of it was...","TWN":"那個發起人果然是……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>도미닉 킹 레지날드</color>.","JPN":"……<color=#ffd34c>ドミニーク・キング・レジナルド</color>。","ENG":"...<color=#ffd34c>Dominic King Reginald</color>.","TWN":"……<color=#ffd34c>多明尼克·金·雷吉納德</color>。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 운명이라는 건 참 짓궂군.","JPN":"ふふ、運命とは実に皮肉なものだな。","ENG":"Ha ha, fate can be so cruel.","TWN":"呵呵，真是造化弄人。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아무래도 세계가 달라진다고 해서 사람의 본질 자체가 달라지지는 않는 모양이야.","JPN":"どうやら世界は違っても人間の本質は変わらないようだ。","ENG":"Perhaps, even if the world is different, the essence of a person is not.","TWN":"看來，即使世界發生了變化，人的本質也不會改變。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇다면, 자네는 어떨까?","JPN":"ならば、君はどうだろう？","ENG":"Then, I wonder if you have changed at all.","TWN":"那麼，你呢？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_QM","text":{"KOREA":"……으으.","JPN":"……うう。","ENG":"...Ugh.","TWN":"……呃。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"비상 동결 처리된 다른 실험체들은 전멸인가.","JPN":"非常凍結処理された他の実験体は全滅か。","ENG":"It seems like all the other test subjects who were in emergency cryostasis died.","TWN":"其他被緊急凍結的實驗體都死了嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"실험체 코드, <color=#ffd34c>AL-0195K</color>. 본명, 레베카 카트린느.","JPN":"実験コード、<color=#ffd34c>AL-0195K</color>。本名、レベッカ・カトリーヌ。","ENG":"Test subject code, <color=#ffd34c>AL-0195K</color>. Name: Rebecca Catherine.","TWN":"實驗體代碼，<color=#ffd34c>AL-0195K</color>。本名是蕾貝卡·卡特琳娜"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"분명, 우리 세계에서는 레지날드 준장의 부대 소속의 선봉대였지.","JPN":"確か、我々の世界ではレジナルド准将の部隊の切り込み役だったな。","ENG":"You were, in our world, the vanguard for Brigadier General Reginald's unit.","TWN":"在我的世界裡，你隸屬於多明尼克準將部隊的先鋒隊。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"당신은 누구지?","JPN":"お前誰だ？","ENG":"Who are you?","TWN":"你是誰？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"세계의 멸망은, 약속의 땅은…… 낙원은……?","JPN":"世界の滅亡は、約束の地は……楽園は……？","ENG":"What about the end of the world, the promised land... paradise...?","TWN":"世界滅亡？約定之地？……樂，樂園……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"약속의 땅? 낙원? 종교적인 뉘양스의 단어들이군.","JPN":"約束の地？　楽園？　どれも宗教的ニュアンスのある単語だな。","ENG":"The promised land? Paradise? Quite the religious choice of words.","TWN":"約定之地？樂園？這些充滿宗教色彩的詞語。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"약물적인 실험 외에도 지속적인 세뇌 작업을 병행한 건가?","JPN":"薬物による実験の他に、持続的な洗脳も並行して行っていたのか？","ENG":"Did they also conduct continuous brainwashing besides the drug trials?","TWN":"除了藥物試驗以外，還替你洗腦嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"나는, 나는 살고 싶어…….","JPN":"オレは、オレは生きたい……","ENG":"I... I want to live...","TWN":"我，我想活下去……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"미안하지만, 나도 역시 도망자 신세라서 낙원 같은 걸 약속할 수는 없네.","JPN":"申し訳ないが、私も逃亡者だ。楽園なんて約束できる身分ではない。","ENG":"Unfortunately, I am also a fugitive, so I cannot promise you paradise.","TWN":"很抱歉，我也在逃亡，沒法跟你做樂園之類的約定。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"이건, 야구 배트……?","JPN":"これは、野球バット？","ENG":"Is that... a baseball bat...?","TWN":"這是，棒球棒……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 그럼에도 살고 싶다면, 나와 함께 새로운 세계로 나아가길 원한다면.","JPN":"しかし、それでも生きたいのなら。私と共に新しい世界へ進みたいのなら。","ENG":"But if you wish to live, if you want to head to a new world with me...","TWN":"即便如此，如果你還想活下去，願意同我一起前往新世界的話。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 배트를 손에 쥐게.","JPN":"そのバットを手に取りたまえ。","ENG":"Take the baseball bat.","TWN":"就拿起那根球棒。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그건, 원래부터 자네의 물건이었으니까 말이야.","JPN":"それは、もともと君の物だったのだからな。","ENG":"After all, you were always its owner.","TWN":"那個，原本就是你的東西。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제1 지구 사령 본부, 회의실","JPN":"人類統合防衛軍第1地区指令本部、会議室","ENG":"Conference room, United Humankind Defense Force, 1st District","TWN":"人類共同保衛軍第一區司令總部會議室"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"아, 왔나? 평소에 자네 답지 않게 조금 늦었군.","JPN":"ああ、来たか。少し遅れるとは、いつもの君らしくないな。","ENG":"Oh, you're here. A little late. That's not like you.","TWN":"喔，你來了？居然會晚到，一點都不像平常的你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"죄송합니다. 사령관님.","JPN":"申し訳ありません。司令官。","ENG":"My apologies, Commander.","TWN":"對不起，司令官。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"와아, 사령관 아저씨 오랜만이에요.","JPN":"わあ、司令官のおじさん、お久しぶりです。","ENG":"Whoa, long time no see, Commander.","TWN":"嘿嘿，好久不見，司令官大叔。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨, 몇 번이나 말했잖아요. 총사령관님 앞에서는 예의를 갖추라고요!","JPN":"シノンさん、何度も言っているでしょう。総司令官の前では礼儀正しくしてくださいって！","ENG":"Shiyoung, how many times did I tell you? You need to be respectful toward the Commander-in-chief!","TWN":"時雨，我說過幾次了，在總司令官面前要保持禮貌！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"아니, 됐네. 그쪽 분은 군 소속도 아닌데 군인의 예의를 강요할 수는 없지.","JPN":"いや、問題ない。そちらは軍の人間ではないのだから軍人の礼儀を押し付けることはできんだろう。","ENG":"No, it's not a problem. She is not even in the military, so I cannot compel her to adhere to soldier courtesy.","TWN":"沒事，算了。她也不隸屬於軍隊，不必遵守軍人的禮儀。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"제7 방위선에서 있었던 일은 보고 받았네.","JPN":"第7防衛線での出来事は聞いている。","ENG":"I heard what happened at the 7th Defense Line.","TWN":"我收到了關於第七防線事件的報告。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"괜찮나? 아무래도 상심이 클 것 같네만.","JPN":"大丈夫なのかね？　君の傷心は察するに難くない。","ENG":"Are you all right? You must be distressed.","TWN":"還好嗎？你看起來受了很大打擊。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"군인은 임무를 위해서 언제나 냉철함을 유지해야 한다고 상관에게 배웠습니다.","JPN":"軍人たるもの、任務のためには常に冷静さを保つ必要があると上官から教わっております。","ENG":"I learned from my superior that we soldiers must remain cool-headed while on our missions.","TWN":"長官教過我，身為軍人，為了任務要始終保持冷靜。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무엇보다 제가 여기서 주저 앉아버린다면, 앞서간 대원들을 볼 면목이 없을 테니까요.","JPN":"それと何より、私がここで折れてしまっては、先立った隊員たちに顔向けできません。","ENG":"But most of all, I cannot face those who have fallen before me if I give up here.","TWN":"如果我就此一蹶不振，就沒有臉面去面對那些犧牲的隊員。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"훌륭하군.","JPN":"立派だな。","ENG":"Excellent answer.","TWN":"不錯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그보다 상황은 어떻습니까? 저희가 이곳에 머무는 동안 아종 네피림은 어떻게 되었죠?","JPN":"それより状況を聞かせてください。私たちがこちらに滞在している間、亜種ネフィリムはどうなりましたか？","ENG":"But how is the current situation? What happened to the Nephil subspecies while we were staying here?","TWN":"所以，情況如何？我們在這裡逗留的期間，那隻亞種諾菲力呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"그다지 좋지는 않아.","JPN":"あまり良い状況ではない。","ENG":"It’s not looking good.","TWN":"情況不樂觀。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"식별명, <color=#ffd34c>아포리아</color>.","JPN":"識別名、<color=#ffd34c>アポリア</color>。","ENG":"Code Name: <color=#ffd34c>Aporia</color>.","TWN":"識別名為<color=#ffd34c>阿波利亞</color>。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"자네가 관리하던 제7 방위선이 함락된 지금, 아포리아는 제6 방위선을 돌파중이네.","JPN":"君が仕切っていた第7防衛線が陥落した今、アポリアは第6防衛線を突破しようとしている。","ENG":"The 7th Defense Line, which you were in charge of, is destroyed, and Aporia is currently trying to break through the 6th Defense Line.","TWN":"目前你管理的第七防線已淪陷，阿波利亞正在嘗試突破第六防線。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_EXILER_NPC_NULL","text":{"KOREA":"우리 대원들이 필사적으로 항전하고 있지만, 아마도 시간 문제겠지.","JPN":"隊員たちが必死に抗戦しているが、それも時間の問題だろう。","ENG":"Our troops are doing their best to stop it, but I'm afraid it's only a matter of time.","TWN":"雖然我們的隊員們正在拼命抵抗，但撐不了多久的。"},"stage":{"bg":"MAINSTREAM_5201002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아포리아, 그야말로 난제로군요.","JPN":"アポリア、非常に難しい問題ですね。","ENG":"Aporia, it literally is a conundrum.","TWN":"阿波利亞，真是太難對付了。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"잠깐, 네피림 사태 때와는 뭔가 다른 점도 있어.","JPN":"ちょっと待ってくれ、ネフィリムのときとは異なる点もあるんだ。","ENG":"Hold on, there's something different from the Nephil incident.","TWN":"等一下，他好像和諾菲力事件的時候有些不同。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"네피림 사태 때를 떠올려봐. 그 괴물에게는 원래 목적 같은 게 없었어.","JPN":"ネフィリムのときを思い出してみてくれ。あの化け物には目的なんてなかった。","ENG":"Go back to the Nephil incident. That monster had no objective.","TWN":"那時候，這種怪物並沒有特定的攻擊目標。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그저 다른 침식체들처럼 눈 앞에 보이는 모든 걸, 닥치는 대로 박살내고 다녔을 뿐이지.","JPN":"ただ他の侵食体同様、目につくものを手あたり次第破壊して周っていただけだった。","ENG":"It just destroyed everything in its path like any other C.O.","TWN":"諾菲力和其他侵蝕體一樣，只會肆意地破壞和粉碎眼前看到的一切。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"하지만 아포리아는 달라.","JPN":"でもアポリアは違う。","ENG":"But Aporia's different.","TWN":"但阿波利亞不一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"느리지만 천천히, 확실하게 세계 이곳저곳을 뒤집어 놓고 있어.","JPN":"ゆっくりだけど、確実に世界のあちこちをひっくり返している。","ENG":"Slowly but surely, it's causing havoc all around the world.","TWN":"行動雖然緩慢，卻在世界各地都製造了襲擊。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"마치 뭔가를 찾고 있는 것처럼.","JPN":"まるで何かを探しているみたいに。","ENG":"It is as if it's looking for something.","TWN":"就像……就像在尋找什麼。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭔가를 찾고 있다고요?","JPN":"何かを探している？","ENG":"Looking for something?","TWN":"尋找什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"잠깐, 그러고보니…….","JPN":"そういえば……","ENG":"Wait, come to think of it...","TWN":"等等，我想起來了……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CYBERCAT_DELTA_NULL_NULL","text":{"KOREA":"시간 없어! 격벽을 내릴 테니까, 신호하면 뛰어!","JPN":"時間がないわ！　隔壁を降ろすから、合図したら走って！","ENG":"There's no time! I'll lower the wall, so run for it on my signal!","TWN":"沒時間了！我會降下隔離牆，一發信號你就跑！"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CYBERCAT_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 네피림!","JPN":"ね、ネフィリム！","ENG":"N-Nephil!","TWN":"諾，諾菲力!"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KING_EXILER_NULL_QM","text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KING_EXILER_NULL_QM","text":{"KOREA":"<color=#ff3636>죽인다.</color>","JPN":"<color=#ff3636>殺す。</color>","ENG":"<color=#ff3636>Kill.</color>","TWN":"<color=#ff3636>死。</color>"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네피림이 말을……?","JPN":"まさか喋れるの……？","ENG":"The Nephil's... talking...?","TWN":"諾菲力……說話了？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KING_EXILER_NULL_QM","text":{"KOREA":"<color=#ff3636>방해하면 죽인다.</color>","JPN":"<color=#ff3636>邪魔をすれば殺す。</color>","ENG":"<color=#ff3636>Disturb me, and I'll kill you.</color>","TWN":"<color=#ff3636>妨礙者……死。</color>"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아포리아가 말을 했다고?","JPN":"アポリアが喋ったって？","ENG":"Aporia spoke?","TWN":"阿波利亞會說話？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 틀림없이 방해하지 말라는 말을 들었어요.","JPN":"はい、確かに邪魔をするなと言っていました。","ENG":"Yes, I heard it clearly tell me not to disturb it.","TWN":"是，我清楚地聽到他說不要妨礙他。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"방해하지 말라는 건, 분명 어떤 목표를 가지고 있다는 뜻.","JPN":"邪魔をするなということは、何らかの目的があるということでしょう。","ENG":"If it doesn't want to be disturbed, then it must have some kind of objective in mind.","TWN":"不要妨礙他，就說明他確實有著某種目的。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어쩌면 아포리아의 목적을 알아내는 것이 공략의 첫걸음이 될지도 모르겠군요.","JPN":"もしかすると、アポリアの目的を知ることが、攻略の第一歩になるかもしれませんね。","ENG":"Perhaps finding out its objective is our first step in defeating it.","TWN":"或許，我們可以先瞭解阿波利亞的目的是什麼，然後再找對策將其擊敗。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"잠깐, 공략이라고요?","JPN":"今、攻略といいました？","ENG":"Hold on. Defeat it?","TWN":"等等，你說擊敗他？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"잊지는 않았겠죠, 카린 양?","JPN":"まさか忘れたわけじゃないですよね、カリンさん？","ENG":"I hope you didn't forget, Karin.","TWN":"你沒失憶吧，卡琳？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"모습은 다르지만, 그건 우리 세계를 한번 끝장낼 뻔한 고위 침식체라고요.","JPN":"見た目は違いますが、あれは私たちの世界を一度滅ぼしかけた高位侵食体なんですよ。","ENG":"It may look different, but that is a high-tier C.O. that almost ended our world once.","TWN":"雖然樣貌不同，但那是差一點毀滅了我們世界的高階侵蝕體。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런 존재와 다시 싸운다는 게 어떤 의미인 줄 아시는 거죠?","JPN":"それともう一度戦うことが、どんな意味を持つかわかりますよね？","ENG":"Do you know what it means to go up against something like that again?","TWN":"你知道再次和他戰鬥代表什麼意思嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이번에야말로 진짜 모두 목숨을 잃을지도 모른다고요.","JPN":"今度こそ、本当に全滅するかもしれないんですよ。","ENG":"It could really be the end of us this time.","TWN":"說不定大家這次真的都會喪命。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이미 멸망이 확정된 이 세계에서는 아무것도 할 수 없고, 아무도 구할 수 없어.","JPN":"すでに滅亡が確定したこの世界では、手を打つことも、誰かを救うこともできない。","ENG":"In a world where destruction is determined, there is nothing you can do to save it or its people.","TWN":"在這個註定滅亡的世界裡，什麼也做不了，什麼也拯救不了。"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어떤가, 소령? 나와 함께 관리국이 존재하는 세계로 나아가지 않겠나?","JPN":"どうだ、少佐？　私と共に管理局のある世界に行かないか？","ENG":"What will it be, Major? Will you join me and head to the world where the Administration exists?","TWN":"怎麼樣，少校？要和我一起前往管理局所在的世界嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요.","JPN":"いいえ。","ENG":"I don't think so.","TWN":"不。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"설령 이 목숨을 다한다고 해도, 꼴사납게 도망치거나 포기하지 않을 거예요.","JPN":"たとえこの命が尽きようとも、惨めに逃げたり諦めたりはしません。","ENG":"Even if it means that I die, I won't be a coward and run away or give up.","TWN":"就算拼了這條命，我也不會狼狽地逃跑或放棄。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 싸울 거예요. 마지막에, 마지막까지.","JPN":"私は戦います。最後の最後まで。","ENG":"I'm going to fight. Until the very last second.","TWN":"我要戰鬥，戰鬥到底。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까 염치없는 부탁일지도 모르겠지만……","JPN":"だから、自分勝手なお願いかもしれませんが……","ENG":"So, it may be arrogant of me to ask this, but...","TWN":"所以，這個請求可能有些厚臉皮……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저와 함께 싸워주세요, 시영 씨.","JPN":"私と一緒に戦ってください、シノンさん。","ENG":"I want you to fight alongside me, Shiyoung.","TWN":"但請和我一起戰鬥吧，時雨。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하아, 정말이지. 비지니스는 정에 휘둘리면 안 되는데.","JPN":"はぁ、まったく。ビジネスは情に左右されちゃいけないんですけどね。","ENG":"*Sigh* C'mon. I shouldn't be swayed by personal feelings when conducting business.","TWN":"哀哀，真是的，做生意可不能感情用事。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래도 역시 카린 양이 그런 눈으로 부탁하면 어쩔 수 없네요.","JPN":"でもやっぱり、カリンさんにそんな目でお願いされたら、仕方がありませんよね。","ENG":"But if Karin asks me with those eyes, how can I not?","TWN":"但卡琳你用這種眼神拜託我，叫我怎麼有辦法拒絕。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"좋아요, 함께 싸워요.","JPN":"いいでしょう。一緒に戦います。","ENG":"Okay, let's do this together.","TWN":"好，一起戰鬥吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 대신 보수는 넉넉하게 챙겨주시는 거예요?","JPN":"その代わり報酬はたっぷりくださいよ？","ENG":"But you have to pay me handsomely, okay?","TWN":"不過，報酬你會多給點吧?"},"stage":{"bg":"MEETING_ROOM","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};